import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import Add from "./Add";
import Results from "./Results";
import style from "../style/App.module.css";
import {
  CURRENCY_OPTIONS,
  filterMovimientosByCurrency,
  formatMoney,
  getAverageTicket,
  getCurrencyMeta,
  getTopCategory,
  isSameMonth,
  summarizeByType,
} from "../utils/finance";

function Dashboard({
  movimientos = [],
  refreshKey,
  onMovementUpdate,
  movementToEdit,
  setMovementToEdit,
  currentCurrency,
  onCurrencyChange,
  ...authProps
}) {
  const navigate = useNavigate();
  const [showOnly, setShowOnly] = useState(null);

  const handleEditClick = (movimiento) => {
    setMovementToEdit?.(movimiento);
    navigate("/add");
  };

  const currencyMovimientos = useMemo(
    () => filterMovimientosByCurrency(movimientos, currentCurrency),
    [movimientos, currentCurrency]
  );

  const monthMovimientos = useMemo(
    () => currencyMovimientos.filter((movimiento) => isSameMonth(movimiento.fecha)),
    [currencyMovimientos]
  );

  const summary = useMemo(
    () => summarizeByType(currencyMovimientos),
    [currencyMovimientos]
  );

  const monthSummary = useMemo(
    () => summarizeByType(monthMovimientos),
    [monthMovimientos]
  );

  const topExpense = useMemo(
    () => getTopCategory(monthMovimientos, "egreso"),
    [monthMovimientos]
  );

  const avgTicket = useMemo(
    () => getAverageTicket(monthMovimientos),
    [monthMovimientos]
  );

  const currencyMeta = getCurrencyMeta(currentCurrency);

  return (
    <div className={style.page}>
      <section className={style.hero}>
        <div className={style.heroCopy}>
          <p className={style.eyebrow}>Resumen financiero</p>
          <h1>Controla ingresos, egresos y notas con una vista mas clara.</h1>
          <p className={style.heroText}>
            El panel filtra todo por moneda para que no mezcles cajas. Hoy estas
            mirando {currencyMeta.label.toLowerCase()}.
          </p>
        </div>

        <div className={style.heroControls}>
          <div className={style.currencySwitch}>
            {CURRENCY_OPTIONS.map((option) => (
              <button
                key={option.value}
                type="button"
                className={`${style.currencyButton} ${
                  currentCurrency === option.value ? style.currencyButtonActive : ""
                }`}
                onClick={() => onCurrencyChange?.(option.value)}
              >
                {option.codeLabel}
              </button>
            ))}
          </div>

          <div className={style.quickActions}>
            <button
              type="button"
              className={style.incomeAction}
              onClick={() => setShowOnly("ingreso")}
            >
              Nuevo ingreso
            </button>
            <button
              type="button"
              className={style.expenseAction}
              onClick={() => setShowOnly("egreso")}
            >
              Nuevo egreso
            </button>
          </div>
        </div>
      </section>

      <section className={style.metricsGrid}>
        <article className={style.metricCard}>
          <span>Saldo acumulado</span>
          <strong>{formatMoney(summary.total, currentCurrency)}</strong>
          <small>{currencyMovimientos.length} movimientos en total</small>
        </article>

        <article className={style.metricCard}>
          <span>Ingresos del mes</span>
          <strong>{formatMoney(monthSummary.ingreso, currentCurrency)}</strong>
          <small>Dinero que entro este mes</small>
        </article>

        <article className={style.metricCard}>
          <span>Egresos del mes</span>
          <strong>{formatMoney(monthSummary.egreso, currentCurrency)}</strong>
          <small>Dinero que salio este mes</small>
        </article>

        <article className={style.metricCard}>
          <span>Ticket promedio</span>
          <strong>{formatMoney(avgTicket, currentCurrency)}</strong>
          <small>Promedio por movimiento del mes</small>
        </article>

        <article className={style.metricCardWide}>
          <span>Categoria con mayor egreso</span>
          <strong>
            {topExpense
              ? `${topExpense.categoria} · ${formatMoney(
                  topExpense.monto,
                  currentCurrency
                )}`
              : "Todavia no hay egresos en esta moneda"}
          </strong>
          <small>
            Sirve para detectar rapido donde se concentra la salida de caja.
          </small>
        </article>
      </section>

      {showOnly && (
        <section className={style.inlineForm}>
          <div className={style.inlineFormHeader}>
            <div>
              <p className={style.inlineFormEyebrow}>
                Cargar {showOnly === "ingreso" ? "ingreso" : "egreso"}
              </p>
              <h2>Guarda movimientos en pesos o dolares desde el mismo flujo.</h2>
            </div>

            <button
              type="button"
              className={style.closeInlineForm}
              onClick={() => setShowOnly(null)}
            >
              Cerrar
            </button>
          </div>

          <Add
            onMovementAdded={() => {
              onMovementUpdate?.();
              setShowOnly(null);
            }}
            movementToEdit={movementToEdit}
            only={showOnly}
            defaultCurrency={currentCurrency}
          />
        </section>
      )}

      <Results
        movimientos={movimientos}
        refreshKey={refreshKey}
        onEditClick={handleEditClick}
        onMovementUpdate={onMovementUpdate}
        currentCurrency={currentCurrency}
        {...authProps}
      />
    </div>
  );
}

export default Dashboard;
